struct Node{int data;struct Node*next;};

struct Node*newNode(int v){struct Node* n=(struct Node*)malloc(sizeof(struct Node));n->data=v;n->next=NULL;return n;}

void append(struct Node**head,int v){struct Node* n=newNode(v);if(*head==NULL){*head=n;return;}struct Node*cur=*head;while(cur->next)cur=cur->next;cur->next=n;}

int search(struct Node*head,int x){int pos=1;while(head){if(head->data==x)return pos;head=head->next;pos++;}return -1;}

