import java.io.*;
import java.util.*;
public class Main {
    static class Node{int data;Node next;Node(int d){data=d;}};
    static Node append(Node head,int v){Node n=new Node(v);if(head==null)return n;Node cur=head;while(cur.next!=null)cur=cur.next;cur.next=n;return head;}
    static int search(Node head,int x){int pos=1;while(head!=null){if(head.data==x)return pos;head=head.next;pos++;}return -1;}
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb=new StringBuilder();
        int T=Integer.parseInt(br.readLine().trim());
        while(T-- > 0){
            int N=Integer.parseInt(br.readLine().trim());
            StringTokenizer st=new StringTokenizer(br.readLine());
            Node head=null;
            for(int i=0;i<N;i++) head=append(head,Integer.parseInt(st.nextToken()));
            int x=Integer.parseInt(br.readLine().trim());
            sb.append(search(head,x)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

